external_knowledge:
- "on the brink of closing" refers to banks that are scheduled to close soon;
- "the next quarter" corresponds to the next three months;
- "enter the realm of dormancy" is a metaphorical expression for closing down or ceasing operations.

sql:
SELECT COUNT(*) 
FROM banks 
WHERE closing_date BETWEEN DATE('now') AND DATE('now', '+3 months');

SELECT bank_name 
FROM banks 
WHERE certification = (
    SELECT MAX(certification) 
    FROM banks
);

SELECT AVG(total_assets) 
FROM banks 
WHERE total_assets > (SELECT AVG(total_assets) FROM banks);

WITH banks_assets AS (
    SELECT SUM(total_assets) AS total_banks_assets
    FROM banks
),
acquiring_institutions_assets AS (
    SELECT SUM(total_assets) AS total_acquiring_institutions_assets
    FROM acquiring_institutions
)
SELECT total_banks_assets - total_acquiring_institutions_assets AS assets_difference
FROM banks_assets, acquiring_institutions_assets;

SELECT state, COUNT(bank_id) AS 'Number of Banks'
FROM banks
GROUP BY state;

SELECT bank_name, city, state, certification, closing_date, ceo_name, total_assets, total_liabilities, total_deposits, number_of_employees, website, last_audited_date
FROM banks
WHERE bank_id = 0;

SELECT bank_name, state
FROM banks
WHERE total_assets > (SELECT AVG(total_assets) FROM banks);

SELECT COUNT(*) 
FROM bank_transactions 
WHERE branch_id = 1;
